// Real grid is auto-generated from GitHub contributions for enzomanuelmangano (2018-2026)
export const CONTRIBUTION_GRID_COLS = 53;
export const CONTRIBUTION_GRID_ROWS = 63;
export const CONTRIBUTION_YEARS = [2018,2019,2020,2021,2022,2023,2024,2025,2026];

/**
 * Set to `true` to use your GitHub snapshot (`REAL_CONTRIBUTION_GRID` below).
 * `false` (default) uses a deterministic synthetic grid for demos / screenshots.
 */
export const USE_REAL_CONTRIBUTION_GRID = false;

/** Smooth float field (box blur) so quantized levels read as foothills / ranges. */
function smoothFloat2D(
  grid: number[][],
  passes: number,
): number[][] {
  const cols = grid.length;
  const rows = grid[0].length;
  let cur = grid.map(column => [...column]);
  for (let p = 0; p < passes; p++) {
    const next: number[][] = [];
    for (let c = 0; c < cols; c++) {
      next[c] = [];
      for (let r = 0; r < rows; r++) {
        let sum = 0;
        let count = 0;
        for (let dc = -1; dc <= 1; dc++) {
          for (let dr = -1; dr <= 1; dr++) {
            const cc = c + dc;
            const rr = r + dr;
            if (cc >= 0 && cc < cols && rr >= 0 && rr < rows) {
              sum += cur[cc][rr];
              count += 1;
            }
          }
        }
        next[c][r] = sum / count;
      }
    }
    cur = next;
  }
  return cur;
}

function fbm2(nx: number, ny: number): number {
  let v = 0;
  let a = 0.48;
  let f = 1;
  for (let i = 0; i < 5; i++) {
    v +=
      a *
      Math.sin((nx * 2.4 + ny * 1.6 + i * 0.4) * f * Math.PI * 2);
    v +=
      a *
      0.55 *
      Math.cos((nx * 1.2 - ny * 2.1 + 0.8) * f * Math.PI * 2);
    a *= 0.5;
    f *= 2.05;
  }
  return v;
}

/**
 * Synthetic terrain: cordillera + massifs + fBM, smoothed then mapped to 0–4.
 * Tuned to read as mountains in the isometric contribution view (not random noise).
 */
function buildAdHocContributionGrid(): number[][] {
  const cols = CONTRIBUTION_GRID_COLS;
  const rows = CONTRIBUTION_GRID_ROWS;
  const nx = (c: number) => c / Math.max(cols - 1, 1);
  const ny = (r: number) => r / Math.max(rows - 1, 1);

  const raw: number[][] = [];
  for (let c = 0; c < cols; c++) {
    const col: number[] = [];
    for (let r = 0; r < rows; r++) {
      const x = nx(c);
      const y = ny(r);
      // Primary range: diagonal cordillera (reads well in iso)
      const along = (x * 0.72 + y * 0.58) * Math.PI * 4.8;
      const cordillera =
        Math.pow(
          (Math.sin(along) * 0.5 + 0.5) * 0.82 +
            Math.sin(along * 2.1 + 0.9) * 0.11 +
            Math.sin(along * 3.7 + 2.1) * 0.07,
          1.25,
        );
      // Distinct summits / plateaus
      const peak = (px: number, py: number, w: number, h: number) =>
        Math.exp(-((x - px) ** 2 + (y - py) ** 2) / w) * h;
      const massifs =
        peak(0.32, 0.38, 0.042, 0.26) +
        peak(0.58, 0.52, 0.036, 0.24) +
        peak(0.44, 0.22, 0.05, 0.2) +
        peak(0.78, 0.35, 0.045, 0.17);
      // Wide basin / valley floor toward one corner
      const basin = Math.pow(x * (1 - x) * y * (1 - y) * 4, 0.55) * 0.14;
      const detail = fbm2(x, y) * 0.2;
      // Crest accent along the main range
      const ridge = (1 - Math.abs(Math.sin(x * 11 + y * 7.5 + 0.4))) * 0.09 * cordillera;

      let h =
        cordillera * 0.44 +
        massifs +
        basin +
        detail +
        ridge;
      col.push(h);
    }
    raw.push(col);
  }

  const smoothed = smoothFloat2D(raw, 3);
  let min = Infinity;
  let max = -Infinity;
  for (const col of smoothed) {
    for (const v of col) {
      if (v < min) min = v;
      if (v > max) max = v;
    }
  }
  const span = max - min || 1;

  const grid: number[][] = [];
  for (let c = 0; c < cols; c++) {
    const col: number[] = [];
    for (let r = 0; r < rows; r++) {
      const t = (smoothed[c][r] - min) / span;
      // More valley / foothill, fewer alpine cells (mountain-shaped histogram)
      let level: number;
      if (t < 0.22) level = 0;
      else if (t < 0.4) level = 1;
      else if (t < 0.58) level = 2;
      else if (t < 0.76) level = 3;
      else level = 4;
      col.push(level);
    }
    grid.push(col);
  }
  return grid;
}

